1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep all cells alive in a block (still life)", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it("should reproduce a dead cell with exactly 3 live neighbors", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
19	  });
20	  it("should transform blinker from vertical to horizontal", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const result = nextGeneration(vertical);
23	    expect(result).toContainEqual([-1, 1]);
24	    expect(result).toContainEqual([0, 1]);
25	    expect(result).toContainEqual([1, 1]);
26	    expect(result).toHaveLength(3);
27	  });
