1	type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter(
5	    ([cx, cy]) =>
6	      Math.abs(cx - cell[0]) <= 1 &&
7	      Math.abs(cy - cell[1]) <= 1 &&
8	      !(cx === cell[0] && cy === cell[1])
9	  ).length;
10	
11	const neighborPositions = ([x, y]: Cell): Cell[] =>
12	  [-1, 0, 1]
13	    .flatMap((dx) => [-1, 0, 1].map((dy) => [x + dx, y + dy] as Cell))
14	    .filter(([nx, ny]) => nx !== x || ny !== y);
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const survivors = cells.filter((cell) => {
18	    const neighborCount = countNeighbors(cell, cells);
19	    return neighborCount === 2 || neighborCount === 3;
20	  });
21	
22	  const birthCandidates = cells
23	    .flatMap(neighborPositions)
24	    .filter(([cx, cy], index, all) =>
25	      !cells.some(([lx, ly]) => lx === cx && ly === cy) &&
26	      all.findIndex(([ax, ay]) => ax === cx && ay === cy) === index
27	    );
28	
29	  const born = birthCandidates.filter(
30	    (cell) => countNeighbors(cell, cells) === 3
31	  );
32	
33	  return [...survivors, ...born];
34	}
